// Helper functions
function getGameQuestions(gameType, level = null) {
    const questions = gameQuestionsDB[gameType] || [];
    if (level) {
        return questions.filter(q => !q.level || q.level === level);
    }
    return questions;
}

function shuffleArray(array) {
    const shuffled = [...array];
    for (let i = shuffled.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled;
}

function getRandomQuestions(gameType, count, level = null) {
    const questions = getGameQuestions(gameType, level);
    return shuffleArray(questions).slice(0, Math.min(count, questions.length));
}

// Export for use
window.gameQuestionsDB = gameQuestionsDB;
window.getGameQuestions = getGameQuestions;
window.getRandomQuestions = getRandomQuestions;
window.shuffleArray = shuffleArray;
